import * as React from 'react';
import CssBaseline from '@mui/material/CssBaseline';
import Paper from '@mui/material/Paper';
import Grid from '@mui/material/Grid';
import { createTheme, ThemeProvider } from '@mui/material/styles';
import { SignInComponent } from '../Components/SignInComponent';
import {Box, Typography } from "@mui/material";

const theme = createTheme();
const ImagenDeFondo = 'url(https://www.businessempresarial.com.pe/wp-content/uploads/2023/03/departamentos-de-lujo-2.jpeg)';


export default function SignInPage() {
  return (
    <ThemeProvider theme={theme}>
      <Grid container component="main" sx={{ height: '100vh', display:"flex", flexDirection:"row"}}>
        <CssBaseline />
        <Grid
          item
          xs={12}
          sm={4}
          md={8}
          sx={{
            maxHeight:"100vh",
            minHeight:150,
            backgroundImage: ImagenDeFondo,
            backgroundRepeat: 'no-repeat',
            backgroundColor: (t) =>
              t.palette.mode === 'light' ? t.palette.grey[50] : t.palette.grey[900],
            backgroundSize: 'cover',
            backgroundPosition: 'center',
          }}
        >
          <Typography variant='h2' sx={{color:"#9c27b0"}}> Teloalquilo.com.pe</Typography>
        </Grid>
        <Grid item xs={12} sm={8} md={4} sx={{height:"100vh", display:"flex", flexDirection:"column"}} component={Paper} elevation={6} square>
          <Grid container sx={{height:"100vh"}}>
            <Grid item sx={{height:"75vh", mb:12}}>
              <SignInComponent/>
            </Grid>
            <Grid item xs={12} sx={{height:"25vh"}}>
              <Box sx={{bgcolor:"#78cd45", border:1, width:"100%", height:"100%"}}>hola</Box>
            </Grid>
          </Grid>
        </Grid>
      </Grid>
    </ThemeProvider>
  );
}
